terraform_example.snippet:
resource "aws_wafv2_ip_set" "admin_trusted" {
  name               = "admin-trusted-cidrs"
  scope              = "REGIONAL"
  ip_address_version = "IPV4"
  addresses          = ["203.0.113.10/32", "198.51.100.0/24"]
}

# Toggle for staged rollout
variable "admin_surface_enforcement" {
  type        = string
  default     = "COUNT"
  validation {
    condition     = contains(["COUNT", "BLOCK"], var.admin_surface_enforcement)
    error_message = "admin_surface_enforcement must be COUNT or BLOCK"
  }
}

resource "aws_wafv2_web_acl" "this" {
  name  = "example-web-acl"
  scope = "REGIONAL"

  default_action { allow {} }

  rule {
    name     = "restrict-admin-surface-to-trusted-cidrs"
    priority = 50

    # Start with COUNT, then switch to BLOCK
    dynamic "action" {
      for_each = var.admin_surface_enforcement == "BLOCK" ? [1] : []
      content { block {} }
    }
    dynamic "action" {
      for_each = var.admin_surface_enforcement == "COUNT" ? [1] : []
      content { count {} }
    }

    statement {
      and_statement {
        statement {
          or_statement {
            statement {
              byte_match_statement {
                field_to_match { uri_path {} }
                positional_constraint = "STARTS_WITH"
                search_string         = "/admin"
                text_transformation {
                  priority = 0
                  type     = "NONE"
                }
              }
            }
            statement {
              byte_match_statement {
                field_to_match { uri_path {} }
                positional_constraint = "STARTS_WITH"
                search_string         = "/wp-admin"
                text_transformation {
                  priority = 0
                  type     = "NONE"
                }
              }
            }
            statement {
              byte_match_statement {
                field_to_match { uri_path {} }
                positional_constraint = "STARTS_WITH"
                search_string         = "/manage"
                text_transformation {
                  priority = 0
                  type     = "NONE"
                }
              }
            }
          }
        }

        statement {
          not_statement {
            statement {
              ip_set_reference_statement {
                arn = aws_wafv2_ip_set.admin_trusted.arn
              }
            }
          }
        }
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "restrictAdminSurfaceToTrustedCidrs"
      sampled_requests_enabled   = true
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "exampleWebAcl"
    sampled_requests_enabled   = true
  }
}
